import requests
import time
from typing import Optional

class OllamaClient:
    def __init__(self, base_url: str = "http://localhost:11434", timeout: float = 30.0):
        self.base_url = base_url
        self.timeout = timeout
        self.headers = {"Content-Type": "application/json"}

    def query(self, model: str, prompt: str, stream: bool = False) -> Optional[dict]:
        url = f"{self.base_url}/api/generate"
        payload = {
            "model": model,
            "prompt": prompt,
            "stream": stream
        }
        try:
            response = requests.post(url, json=payload, headers=self.headers, timeout=self.timeout)
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            print(f"Ollama connection error: {str(e)}")
            return None

    def ping(self) -> bool:
        url = f"{self.base_url}/api/health"
        try:
            response = requests.get(url, timeout=self.timeout)
            return response.status_code == 200
        except requests.exceptions.RequestException:
            return False

from typing import Dict, Any
from datetime import datetime

class ArtifactSchema:
    def __init__(self, type: str, fields: Dict[str, Any]):
        self.type = type
        self.fields = fields

    def to_dict(self) -> Dict[str, Any]:
        return {
            "type": self.type,
            "fields": self.fields
        }

# Define schema for literary artifacts
LITERARY_ARTIFACT_SCHEMA = ArtifactSchema(
    type="literary_artifact",
    fields={
        "id": {"type": "integer", "description": "Unique identifier"},
        "content": {"type": "string", "description": "Generated content"},
        "metadata": {"type": "object", "description": "Additional metadata"},
        "created_at": {"type": "datetime", "description": "Timestamp of creation"}
    }
)

# Define schema for model parameters
MODEL_PARAMS_SCHEMA = ArtifactSchema(
    type="model_params",
    fields={
        "model": {"type": "string", "description": "Model name"},
        "temperature": {"type": "number", "description": "Temperature parameter"},
        "max_tokens": {"type": "integer", "description": "Maximum token count"}
    }
)

# Define schema for processing steps
PROCESSING_STEP_SCHEMA = ArtifactSchema(
    type="processing_step",
    fields={
        "step": {"type": "string", "description": "Processing step name"},
        "input": {"type": "object", "description": "Input data"},
        "output": {"type": "object", "description": "Output data"},
        "timestamp": {"type": "datetime", "description": "Execution timestamp"}
    }
)
